class Solution {
    public int minimizeXor(int num1, int num2) {
        int setBits = Integer.bitCount(num2);
        int result = 0;
        int i = 31;
        while (setBits > 0 && i >= 0) {
            if ((num1 & (1 << i)) != 0) {
                result |= (1 << i);
                setBits--;
            }
            i--;
        }
        while (i >= 0) {
            if ((num1 & (1 << i)) != 0) {
                result |= (1 << i);
            }
            i--;
        }
        return result;
    }
}
